const DarkMode={STORAGE_KEY: 'sadec-dark-mode',init(){const saved=localStorage.getItem(this.STORAGE_KEY);const prefersDark=window.matchMedia('(prefers-color-scheme: dark)').matches;if(saved==='enabled'||(saved===null&&prefersDark)){this.enable();}window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change',(e)=>{if(localStorage.getItem(this.STORAGE_KEY)===null){e.matches ? this.enable(): this.disable();}});this.bindToggle();},enable(){document.documentElement.setAttribute('data-theme','dark');localStorage.setItem(this.STORAGE_KEY,'enabled');this.updateToggleState(true);this.dispatchEvent('dark-mode-enabled');},disable(){document.documentElement.setAttribute('data-theme','light');localStorage.setItem(this.STORAGE_KEY,'disabled');this.updateToggleState(false);this.dispatchEvent('dark-mode-disabled');},toggle(){const isDark=document.documentElement.getAttribute('data-theme')==='dark';isDark ? this.disable(): this.enable();},isEnabled(){return document.documentElement.getAttribute('data-theme')==='dark';},bindToggle(){document.querySelectorAll('[data-dark-mode-toggle]').forEach(btn=>{btn.addEventListener('click',()=>this.toggle());});document.addEventListener('keydown',(e)=>{if(e.altKey&&e.key==='d'){e.preventDefault();this.toggle();}});},updateToggleState(isDark){document.querySelectorAll('[data-dark-mode-toggle]').forEach(btn=>{btn.setAttribute('aria-pressed',isDark.toString());const icon=btn.querySelector('[data-icon]');if(icon){icon.textContent=isDark ? 'light_mode' : 'dark_mode';}});},dispatchEvent(eventName){window.dispatchEvent(new CustomEvent(eventName,{detail:{isDark: this.isEnabled()}}));}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>DarkMode.init());}else{DarkMode.init();}export default DarkMode;